            HEAT.spellTable["UNIT_AURA"] = HEAT.spellTable["SPELL_AURA_APPLIED"]
        end
        if HEAT.spellTable["SPELL_CAST_START"] then
            HEAT.spellTable["UNIT_SPELLCAST_START"] = HEAT.spellTable["SPELL_CAST_START"]
            HEAT.spellTable["UNIT_SPELLCAST_CHANNEL_START"] = HEAT.spellTable["SPELL_CAST_START"] 
        end
